const body     = $('Webhook').first().json.body;
const showroom = $input.item.json.response;
const products = showroom.products || [];
const groups   = showroom.groups   || [];
const layout   = showroom.layoutAttributes || {};

// Build productUuid → { groupTitle, order } lookup
const productGroupMap = {};
groups.forEach(g => {
  (g.productsInfo || []).forEach(p => {
    productGroupMap[p.productUuid] = { groupTitle: g.title || '', order: p.order || 0 };
  });
});

return [{
  json: {
    showroomUuid:    showroom.uuid,
    showroomName:    showroom.name || 'VNTANA Showroom',
    shareLinkUuid:   body.shareLinkUuid || '',
    products,
    groups,
    productGroupMap,
    layout
  }
}];

const data = $('Extract Assets').first().json;
const map  = data.productGroupMap || {};

const rows = data.products.map(a => {
  const g = map[a.uuid] || {};
  return {
    'Asset UUID': a.uuid || '',
    'Asset Name': a.name || '',
    'Style #':    a.styleNumber || a.sku || '',
    'Group':      g.groupTitle || '',
    'Order':      g.order      || '',
    'Quantity':   '',
    'Notes':      ''
  };
});

return rows.map(r => ({ json: r }));

const data = $('Extract Assets').first().json;

const rows = (data.groups || []).map(g => ({
  'Group Title':    g.title || '',
  'Divider Top':    (g.dividers || []).includes('TOP')    ? 'Yes' : 'No',
  'Divider Bottom': (g.dividers || []).includes('BOTTOM') ? 'Yes' : 'No',
  'Visible':        g.visible !== false ? 'Yes' : 'No'
}));

if (rows.length === 0) {
  rows.push({ 'Group Title': '', 'Divider Top': 'No', 'Divider Bottom': 'No', 'Visible': 'Yes' });
}

return rows.map(r => ({ json: r }));

const data   = $('Extract Assets').first().json;
const layout = data.layout || {};

const rows = [
  { 'Field': '— IDENTIFIERS —',  'Value': '',                             'Options / Notes': '' },
  { 'Field': 'Showroom UUID',    'Value': data.showroomUuid,              'Options / Notes': '' },
  { 'Field': 'Showroom Name',    'Value': data.showroomName,              'Options / Notes': 'Reference only' },
  { 'Field': 'Share Link UUID',  'Value': data.shareLinkUuid,             'Options / Notes': 'Used for order entry' },
  { 'Field': '— TYPOGRAPHY —',   'Value': '',                             'Options / Notes': '' },
  { 'Field': 'Font Family',      'Value': layout.FONT_FAMILY        || 'Roboto',   'Options / Notes': 'Roboto / Arial / Times New Roman / Georgia / Courier New' },
  { 'Field': '— COLORS —',       'Value': '',                             'Options / Notes': '' },
  { 'Field': 'Background Color', 'Value': layout.BACKGROUND_COLOR   || '#FFFFFF',  'Options / Notes': 'Hex format e.g. #FFFFFF' },
  { 'Field': 'Text Color',       'Value': layout.TEXT_COLOR         || '#111111',  'Options / Notes': 'Hex format' },
  { 'Field': 'Divider Color',    'Value': layout.DIVIDER_COLOR      || '#E2E2E0',  'Options / Notes': 'Hex format' },
  { 'Field': '— LAYOUT —',       'Value': '',                             'Options / Notes': '' },
  { 'Field': 'Products Per Row', 'Value': layout.PRODUCTS_PER_ROW   || 4,          'Options / Notes': '1 to 5' },
  { 'Field': 'Image Style',      'Value': layout.IMAGE_STYLE        || 'Cover',    'Options / Notes': 'Cover / Contain / Tile' }
];

return rows.map(r => ({ json: r }));
